-- Demo shop data for 黑马点评学习项目。
-- 每个品类补齐到约 20 条，方便测试分类分页和 Redis GEO 附近商户。
ON DUPLICATE KEY UPDATE name = VALUES(name), type_id = VALUES(type_id), images = VALUES(images), area = VALUES(area), address = VALUES(address), x = VALUES(x), y = VALUES(y), avg_price = VALUES(avg_price), sold = VALUES(sold), comments = VALUES(comments), score = VALUES(score), open_hours = VALUES(open_hours), update_time = VALUES(update_time);

ALTER TABLE tb_shop AUTO_INCREMENT = 10200;
